1	import { mkdir, readFile, writeFile } from 'fs/promises'
2	import path from 'path'
3	import XDGAppPaths from 'xdg-app-paths'
4	
5	type AuthFile = {
6	  tokens: Credentials[]
7	}
8	
9	export type Credentials = {
10	  workspaceId: string
11	  token: string
12	  refreshToken?: string
13	}
14	
15	/**
16	 * This class is used to store and retrieve credentials for the Prisma Platform from the user's config directory.
17	 * A given class instance caches loaded credentials in memory.
18	 *
19	 * In the future this class might be adapted to store and retrieve credentials from other locations.
20	 * E.g. keychains or working directory specific locations.
21	 */
22	export class CredentialsStore {
23	  private loadedCredentials?: Credentials[]
24	  private authFilePath: string
25	
26	  /**
27	   * @param authFilePathOverride - Override for the path to the auth file. Can also be set via the PRISMA_PLATFORM_AUTH_FILE environment variable. Useful for testing.
28	   */
29	  constructor(authFilePathOverride?: string) {
30	    this.authFilePath =
31	      process.env.PRISMA_PLATFORM_AUTH_FILE ||
32	      authFilePathOverride ||
33	      path.join(XDGAppPaths({ name: 'prisma-platform' }).config(), 'auth.json')
34	  }
35	
36	  async reloadCredentialsFromDisk(): Promise<void> {
37	    try {
38	      const content = await readFile(this.authFilePath, 'utf-8')
39	      const data = JSON.parse(content) as AuthFile
40	      this.loadedCredentials = data.tokens || []
41	    } catch (error) {
42	      // Fallback if file not exists or invalid JSON
43	      this.loadedCredentials = []
44	    }
45	  }
46	
47	  async storeCredentials(credentials: Credentials): Promise<void> {
48	    await this.reloadCredentialsFromDisk()
49	    const updatedCredentials = [
50	      ...(this.loadedCredentials || []).filter((c) => c.workspaceId !== credentials.workspaceId),
51	      credentials,
52	    ]
53	    this.loadedCredentials = updatedCredentials
54	    await this.writeCredentialsToDisk(updatedCredentials)
55	  }
56	
57	  async deleteCredentials(workspaceId: string): Promise<void> {
58	    await this.reloadCredentialsFromDisk()
59	    const updatedCredentials = (this.loadedCredentials || []).filter((c) => c.workspaceId !== workspaceId)
60	    this.loadedCredentials = updatedCredentials
61	    await this.writeCredentialsToDisk(updatedCredentials)
62	  }
63	
64	  async getCredentials(): Promise<Credentials[]> {
65	    if (this.loadedCredentials === undefined) {
66	      await this.reloadCredentialsFromDisk()
67	    }
68	    return this.loadedCredentials || []
69	  }
70	
71	  async getCredentialsForWorkspace(workspaceId: string): Promise<Credentials | undefined> {
72	    return (await this.getCredentials()).filter((c) => c.workspaceId === workspaceId)[0]
73	  }
74	
75	  private async writeCredentialsToDisk(credentials: Credentials[]): Promise<void> {
76	    const data: AuthFile = { tokens: credentials }
77	    await mkdir(path.dirname(this.authFilePath), { recursive: true })
78	    await writeFile(this.authFilePath, JSON.stringify(data, null, 2))
79	  }
80	}
