### 3. **Generator Handler - The Entry Point**

**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775389182767-jyi16n/packages/generator-helper/src/generatorHandler.ts`

The `generatorHandler` function is the entry point for all generators. It:
1. Reads JSON-RPC messages from stdin
2. Routes `generate` and `getManifest` methods to handler callbacks
3. Writes responses to stderr as JSON-RPC responses

```typescript
export interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

export function generatorHandler(handler: Handler): void {
  const stdinInterface = readline.createInterface({
    input: process.stdin,
    crlfDelay: Infinity,
  })

  stdinInterface.on('line', async (line: string) => {
    const json = JSON.parse(line)

    if (json.method === 'generate' && json.params) {
      try {
        const result = await handler.onGenerate(json.params)
        respond({
          jsonrpc: '2.0',
          result: result,
          id: json.id,
        })
      } catch (_e) {
        // ... error handling
      }
    }

    if (json.method === 'getManifest') {
      // ... manifest handling
    }
  })

  process.stdin.resume()
}

function respond(response: JsonRpc.Response): void {
  process.stderr.write(JSON.stringify(response) + '\n')
}
