export class GeneratorError extends Error {
  name = 'GeneratorError'

  constructor(
    message: string,
    public code?: number,
    public data?: any,
  ) {
    super(message)
    if (data?.stack) {
      this.stack = data.stack
    }
  }
}

export class GeneratorProcess {
  async generate(options: GeneratorOptions): Promise<void> {
    // Spawns child process and communicates via JSON-RPC
  }

  stop(): void {
    // Sends SIGTERM first, SIGKILL after 2 seconds
    // Ensures graceful shutdown
  }

  private handleResponse(data: JsonRpc.Response): void {
    if (JsonRpc.isErrorResponse(data)) {
      const error = new GeneratorError(
        data.error.message,
        data.error.code,
        data.error.data
      )
      this.handlers[data.id].reject(error)
    } else {
      this.handlers[data.id].resolve(data.result)
    }
  }
}
