import type { DMMF } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Maps a Prisma scalar/enum type name to its TypeScript equivalent. */
export function mapFieldType(field: DMMF.Field, enumNames: Set<string>): string {
  const base = toTsType(field.type, enumNames)
  if (field.isList) return `${base}[]`
  if (!field.isRequired) return `${base} | null`
  return base
}

function toTsType(prismaType: string, enumNames: Set<string>): string {
  if (SCALAR_TYPE_MAP[prismaType]) return SCALAR_TYPE_MAP[prismaType]
  if (enumNames.has(prismaType)) return prismaType
  return 'unknown'
}

/** Renders a TypeScript enum declaration from a DMMF enum. */
export function renderEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

/** Renders a TypeScript interface from a DMMF model, including only scalar and enum fields. */
export function renderModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => {
      const optional = !f.isRequired && !f.isList ? '?' : ''
      return `  ${f.name}${optional}: ${mapFieldType(f, enumNames)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/** Renders the create input type for a model (omits auto-generated fields). */
export function renderCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .filter((f) => !f.isGenerated && !f.isUpdatedAt && !hasAutoDefault(f))
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${mapFieldType(f, enumNames)}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Renders the update input type for a model (all fields optional). */
export function renderUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .filter((f) => !f.isId && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => `  ${f.name}?: ${mapFieldType(f, enumNames)}`)
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

/** Renders a where-unique input type using the model's id/unique fields. */
export function renderWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): string {
  const idFields = model.fields.filter((f) => f.isId || f.isUnique)
  const fields = idFields.map((f) => `  ${f.name}?: ${mapFieldType(f, enumNames)}`).join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
}

function hasAutoDefault(field: DMMF.Field): boolean {
  if (!field.hasDefaultValue || !field.default) return false
  if (typeof field.default === 'object' && 'name' in field.default) {
    const name = (field.default as { name: string }).name
    return name === 'autoincrement' || name === 'uuid' || name === 'cuid' || name === 'auto'
  }
  return false
}

/** Renders CRUD methods for a single model as a class. */
export function renderModelClient(model: DMMF.Model): string {
  const name = model.name
  const lower = name[0].toLowerCase() + name.slice(1)
  const pluralPath = `${lower}s`

  return `export class ${name}Client {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string> = {}) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  /** Retrieve all ${name} records. */
  async findMany(): Promise<${name}[]> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}\`, {
      method: 'GET',
      headers: this.#headers,
    })
    if (!response.ok) throw new Error(\`GET /${pluralPath} failed: \${response.status}\`)
    return response.json() as Promise<${name}[]>
  }

  /** Retrieve a single ${name} by unique identifier. */
  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const id = ${renderIdExtraction(model)}
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}/\${id}\`, {
      method: 'GET',
      headers: this.#headers,
    })
    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`GET /${pluralPath}/\${id} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  /** Create a new ${name} record. */
  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`POST /${pluralPath} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  /** Update an existing ${name} record. */
  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = ${renderIdExtraction(model)}
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`PATCH /${pluralPath}/\${id} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  /** Delete a ${name} record. */
  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = ${renderIdExtraction(model)}
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}/\${id}\`, {
      method: 'DELETE',
      headers: this.#headers,
    })
    if (!response.ok) throw new Error(\`DELETE /${pluralPath}/\${id} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }
}`
}

function renderIdExtraction(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique)
  const fieldName = idField?.name ?? 'id'
  return `where.${fieldName}`
}

/** Renders the top-level REST client class that aggregates all model clients. */
export function renderRestClient(models: readonly DMMF.Model[]): string {
  const properties = models
    .map((m) => {
      const lower = m.name[0].toLowerCase() + m.name.slice(1)
      return `  readonly ${lower}: ${m.name}Client`
    })
    .join('\n')

  const assignments = models
    .map((m) => {
      const lower = m.name[0].toLowerCase() + m.name.slice(1)
      return `    this.${lower} = new ${m.name}Client(baseUrl, headers)`
    })
    .join('\n')

  return `export class PrismaRestClient {
${properties}

  constructor(baseUrl: string, headers: Record<string, string> = {}) {
${assignments}
  }
}`
}

/** Renders the file header with generation metadata. */
export function renderHeader(): string {
  return `// This file was generated by @prisma/generator-rest-client. Do not edit manually.
/* eslint-disable */
`
}

