import fs from 'node:fs'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import {
  renderCreateInput,
  renderEnum,
  renderHeader,
  renderModelClient,
  renderModelInterface,
  renderRestClient,
  renderUpdateInput,
  renderWhereUniqueInput,
} from './template'

/**
 * Generates a typed REST API client file from the DMMF datamodel.
 *
 * Writes a single `rest-client.ts` file to the configured output directory
 * containing interfaces, input types, and CRUD client classes for every model
 * in the Prisma schema.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output?.value
  if (!output) {
    throw new Error('@prisma/generator-rest-client requires an output path in the generator block.')
  }

  const content = generateClientCode(options.dmmf)

  await fs.promises.mkdir(output, { recursive: true })
  await fs.promises.writeFile(path.join(output, 'rest-client.ts'), content, 'utf-8')
}

/** Pure function that produces the full REST client source from a DMMF document. */
export function generateClientCode(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel

  const enumNames = new Set(enums.map((e) => e.name))

  const sections: string[] = [renderHeader()]

  for (const enumDef of enums) {
    sections.push(renderEnum(enumDef))
  }

  for (const model of models) {
    sections.push(renderModelInterface(model, enumNames))
    sections.push(renderWhereUniqueInput(model, enumNames))
    sections.push(renderCreateInput(model, enumNames))
    sections.push(renderUpdateInput(model, enumNames))
    sections.push(renderModelClient(model))
  }

  sections.push(renderRestClient(models))

  return sections.join('\n\n') + '\n'
}

