import type { DMMF } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Maps a Prisma scalar/enum type name to its TypeScript equivalent. */
export function mapFieldType(field: DMMF.Field, enumNames: Set<string>): string {
  const base = toTsType(field.type, enumNames)
  if (field.isList) return `${base}[]`
  if (!field.isRequired) return `${base} | null`
  return base
}

function toTsType(prismaType: string, enumNames: Set<string>): string {
  if (SCALAR_TYPE_MAP[prismaType]) return SCALAR_TYPE_MAP[prismaType]
  if (enumNames.has(prismaType)) return prismaType
  return 'unknown'
}

/** Renders a TypeScript enum declaration from a DMMF enum. */
export function renderEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

/** Renders a TypeScript interface from a DMMF model, including only scalar and enum fields. */
export function renderModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => {
      const optional = !f.isRequired && !f.isList ? '?' : ''
      return `  ${f.name}${optional}: ${mapFieldType(f, enumNames)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/** Renders the create input type for a model (omits auto-generated fields). */
export function renderCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .filter((f) => !f.isGenerated && !f.isUpdatedAt && !hasAutoDefault(f))
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${mapFieldType(f, enumNames)}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Renders the update input type for a model (all fields optional). */
export function renderUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .filter((f) => !f.isId && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => `  ${f.name}?: ${mapFieldType(f, enumNames)}`)
